56‚Üí// POST /api/auth/login
57‚Üírouter.post('/login', validate(LoginSchema), async (req, res) => {
58‚Üí  try {
59‚Üí    const { identifier, password } = req.body;
60‚Üí
61‚Üí    // Detect if identifier is email or phone
62‚Üí    // Validate identifier format here with a clear message
63‚Üí    const isEmail = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(identifier);
64‚Üí    const isPhone = /^\+?[0-9\s\-().]{7,20}$/.test(identifier);
65‚Üí    if (!isEmail && !isPhone) {
66‚Üí      return badRequest(res, 'Enter a valid email address or phone number');
67‚Üí    }
68‚Üí
69‚Üí    const authParams: any = { password };
70‚Üí    if (isEmail) {
71‚Üí      authParams.email = identifier;
72‚Üí    } else {
73‚Üí      authParams.phone = identifier;
74‚Üí    }
75‚Üí
76‚Üí    const { data, error } = await supabase.auth.signInWithPassword(authParams);
77‚Üí
78‚Üí    if (error || !data.user || !data.session) {
79‚Üí      return unauthorized(res, 'Invalid email or password');
80‚Üí    }
81‚Üí
82‚Üí    // Fetch role + profile from public.users
83‚Üí    const { data: profile, error: profileError } = await supabaseAdmin
84‚Üí      .from('users')
85‚Üí      .select('id, email, role, full_name')
86‚Üí      .eq('id', data.user.id)
87‚Üí      .single();
88‚Üí
89‚Üí    if (profileError || !profile) {
90‚Üí      return serverError(res, 'Could not load user profile');
91‚Üí    }
92‚Üí
93‚Üí    // For gym_admin, include their gym_id
94‚Üí    let gym_id: string | null = null;
