99‚Üí        .eq('owner_id', data.user.id)
100‚Üí        .single();
101‚Üí      gym_id = gym?.id ?? null;
102‚Üí    }
103‚Üí
104‚Üí    return ok(res, {
105‚Üí      user: { ...profile, gym_id },
106‚Üí      access_token: data.session.access_token,
107‚Üí      refresh_token: data.session.refresh_token,
108‚Üí      expires_at: data.session.expires_at,
109‚Üí    });
110‚Üí  } catch (err) {
111‚Üí    return serverError(res, 'Login error', err);
112‚Üí  }
113‚Üí});
